20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	const baseFor = (item: Item): number => {
24	  if (item.type === "sword") return 100;
25	  return 0;
26	};
27	
28	const quote = (step: QuoteStep): QuoteResult => {
29	  const itemTotalTenths = step.items.reduce(
30	    (sum, item) => sum + baseFor(item) * (10 + FIRST_INSURANCE_RATE * 10),
31	    0,
32	  );
33	  return { premium: Math.ceil(itemTotalTenths / 10) + PROCESSING_FEE };
34	};
35	
36	export const runScenario = (scenario: Scenario): ScenarioResult => {
37	  return { results: scenario.steps.map(quote) };
38	};
